-                metric,
-                hours ?? 24,
-                serviceName,
-                ct).ConfigureAwait(false);
-
-            return Results.Ok(result);
-        }
-        catch (ArgumentException ex)
-        {
-            return Results.ValidationProblem(new Dictionary<string, string[]>
-            {
-                ["metric"] = [ex.Message]
-            });
-        }
-    }
