-
-        Output ONLY valid JSON with this structure:
-        {
-          "plan_summary": "<one sentence describing the fix>",
-          "steps": [
-            {
-              "file_path": "<relative file path from repo root>",
-              "change_type": "modify|add|delete",
-              "description": "<what to change in this file>",
