-            ["redirect_uri"] = options.OAuthCallbackUrl,
-            ["scope"] = scopes ?? DefaultScopes,
-            ["state"] = state,
-            ["code_challenge"] = codeChallenge,
-            ["code_challenge_method"] = "S256"
-        };
