-            ? $"{plainText[..240]}..."
-            : plainText;
-
-        Dictionary<string, object?> card = new(StringComparer.Ordinal)
-        {
-            ["type"] = "AdaptiveCard",
-            ["$schema"] = "http://adaptivecards.io/schemas/adaptive-card.json",
-            ["version"] = "1.5",
-            ["body"] = new object[]
-            {
-                new Dictionary<string, object?>
-                {
-                    ["type"] = "TextBlock",
-                    ["text"] = "qyl Enterprise Copilot Report",
-                    ["weight"] = "Bolder",
-                    ["size"] = "Medium"
-                },
-                new Dictionary<string, object?>
-                {
-                    ["type"] = "TextBlock",
-                    ["text"] = $"Generated {TimeProvider.System.GetUtcNow():u}",
-                    ["isSubtle"] = true,
-                    ["wrap"] = true
-                },
-                new Dictionary<string, object?>
-                {
-                    ["type"] = "TextBlock",
-                    ["text"] = summary,
-                    ["wrap"] = true
-                },
-                new Dictionary<string, object?>
-                {
-                    ["type"] = "TextBlock",
-                    ["text"] = "Details",
-                    ["weight"] = "Bolder",
-                    ["spacing"] = "Medium"
-                },
-                new Dictionary<string, object?>
-                {
-                    ["type"] = "TextBlock",
-                    ["text"] = plainText,
-                    ["wrap"] = true
-                }
-            }
-        };
-
-        return JsonSerializer.Serialize(card);
-    }
